// ============================================
// AGENTE ESTRATEGA - VERSIÓN CORREGIDA v2.0
// ============================================
// CORRECCIONES:
// 1. Usa precios correctos del símbolo desde _extracted y market_data
// 2. Validación de rangos de precios por símbolo
// 3. Stop loss y take profit con ratios correctos
// ============================================

const inputData = $input.all()[0].json;

console.log("========================================");
console.log("🎯 AGENTE ESTRATEGA v2.0 - INICIANDO");
console.log("========================================");

// ============================================
// CONFIGURACIÓN DE VALIDACIÓN DE PRECIOS
// ============================================
const VALID_RANGES = {
    EURUSD: { min: 1.05, max: 1.20 },
    GBPUSD: { min: 1.25, max: 1.40 },
    USDJPY: { min: 140.0, max: 170.0 },
    USDCHF: { min: 0.85, max: 1.00 }
};

const DEFAULT_PRICES = {
    EURUSD: 1.1689,
    GBPUSD: 1.3570,
    USDJPY: 159.88,
    USDCHF: 0.7996
};

function validatePriceForSymbol(symbol, price) {
    const range = VALID_RANGES[symbol];
    if (!range) return { valid: true, price };

    if (price === null || price === undefined || isNaN(price) || price === 0) {
        console.log(`⚠️ ${symbol}: Precio inválido ${price}, usando default`);
        return { valid: false, price: DEFAULT_PRICES[symbol] };
    }

    if (price < range.min || price > range.max) {
        console.log(`⚠️ ${symbol}: Precio ${price} FUERA DE RANGO [${range.min}-${range.max}]`);
        return { valid: false, price: DEFAULT_PRICES[symbol] };
    }

    return { valid: true, price };
}

// ============================================
// EXTRAER DATOS DE Parse Unificado (_extracted)
// ============================================
let decision = "hold";
let confidence = 0;
let entryPrice = 0;
let stopPrice = 0;
let tp1Price = 0;
let tp2Price = 0;
let volumeValue = 0.05;

// Obtener el símbolo del par actual
let currentSymbol = "EURUSD";
try {
    if (inputData.original?.market_data?.best_pair) {
        currentSymbol = inputData.original.market_data.best_pair;
    } else if (inputData.market_data?.best_pair) {
        currentSymbol = inputData.market_data.best_pair;
    } else if (inputData._extracted?.symbol) {
        currentSymbol = inputData._extracted.symbol;
    }
} catch(e) {
    console.log("⚠️ No se pudo determinar símbolo, usando EURUSD");
}

console.log(`📊 Símbolo actual: ${currentSymbol}`);

// Buscar datos en diferentes ubicaciones
if (inputData._extracted) {
    console.log("✅ Leyendo de _extracted");
    decision = inputData._extracted.decision || "hold";
    confidence = inputData._extracted.confidence || 0;
    const entry = inputData._extracted.entry || [0, 0];
    const stop = inputData._extracted.stop || [0, 0];
    entryPrice = entry[0] || 0;
    stopPrice = stop[0] || 0;
    tp1Price = inputData._extracted.tp1 || 0;
    tp2Price = inputData._extracted.tp2 || 0;
    volumeValue = inputData._extracted.volume || 0.05;
} else if (inputData.state && inputData.state.tecnico) {
    console.log("✅ Leyendo de state");
    const tech = inputData.state.tecnico;
    decision = tech.señal || "hold";
    confidence = tech.confianza || 0;
    const entry = tech.entry_zona || [0, 0];
    const stop = tech.stop_zona || [0, 0];
    entryPrice = entry[0] || 0;
    stopPrice = stop[0] || 0;
    tp1Price = tech.take_profit_1 || 0;
    tp2Price = tech.take_profit_2 || 0;
} else if (inputData.decision) {
    console.log("✅ Leyendo directamente del input");
    decision = inputData.decision || "hold";
    confidence = inputData.confianza || 0;
    entryPrice = inputData.entrada?.precio || 0;
    stopPrice = inputData.stop_loss?.precio || 0;
    tp1Price = inputData.take_profit?.objetivo1 || 0;
    tp2Price = inputData.take_profit?.objetivo2 || 0;
    volumeValue = inputData.volumen || 0.05;
}

// ============================================
// VALIDAR Y CORREGIR PRECIO DE ENTRADA
// ============================================
const priceValidation = validatePriceForSymbol(currentSymbol, entryPrice);
entryPrice = priceValidation.price;

if (!priceValidation.valid) {
    console.log(`🔧 Precio corregido para ${currentSymbol}: ${entryPrice}`);
}

// Si no hay datos válidos, usar valores por defecto basados en el símbolo
if (decision === "hold" || confidence === 0) {
    console.log("⚠️ No se encontraron datos válidos, usando valores por defecto");

    // Obtener precio del contexto para el símbolo correcto
    let price = DEFAULT_PRICES[currentSymbol];

    try {
        if (inputData.original?.market_data?.all_prices?.[currentSymbol]) {
            const ctxPrice = inputData.original.market_data.all_prices[currentSymbol];
            const ctxValidation = validatePriceForSymbol(currentSymbol, ctxPrice);
            if (ctxValidation.valid) {
                price = ctxPrice;
            }
        } else if (inputData.original?.market_data?.technical?.current_price) {
            const ctxPrice = inputData.original.market_data.technical.current_price;
            const ctxValidation = validatePriceForSymbol(currentSymbol, ctxPrice);
            if (ctxValidation.valid) {
                price = ctxPrice;
            }
        }
    } catch(e) {
        console.log("⚠️ No se pudo obtener precio del contexto");
    }

    entryPrice = price;
    decision = "buy"; // Fallback conservador
    confidence = 50;
    console.log(`💰 Precio fallback para ${currentSymbol}: ${price}`);
}

// ============================================
// CÁLCULO DE STOP LOSS Y TAKE PROFIT
// ============================================
// Validar que SL y TP estén en rango correcto
const slValidation = validatePriceForSymbol(currentSymbol, stopPrice);
const tp1Validation = validatePriceForSymbol(currentSymbol, tp1Price);
const tp2Validation = validatePriceForSymbol(currentSymbol, tp2Price);

stopPrice = slValidation.valid ? stopPrice : 0;
tp1Price = tp1Validation.valid ? tp1Price : 0;
tp2Price = tp2Validation.valid ? tp2Price : 0;

// Calcular SL/TP si son inválidos o cero
const isJPY = currentSymbol.includes("JPY");
const slPips = isJPY ? 30 : 0.0030;
const tp1Pips = isJPY ? 50 : 0.0050;
const tp2Pips = isJPY ? 80 : 0.0080;

if (stopPrice === 0) {
    stopPrice = decision === "buy" ? entryPrice - slPips : entryPrice + slPips;
}

if (tp1Price === 0) {
    tp1Price = decision === "buy" ? entryPrice + tp1Pips : entryPrice - tp1Pips;
}

if (tp2Price === 0) {
    tp2Price = decision === "buy" ? entryPrice + tp2Pips : entryPrice - tp2Pips;
}

// Validar lógica de SL/TP
if (decision === "buy") {
    if (stopPrice >= entryPrice) stopPrice = entryPrice - slPips;
    if (tp1Price <= entryPrice) tp1Price = entryPrice + tp1Pips;
    if (tp2Price <= tp1Price) tp2Price = tp1Price + (tp2Pips - tp1Pips);
} else if (decision === "sell") {
    if (stopPrice <= entryPrice) stopPrice = entryPrice + slPips;
    if (tp1Price >= entryPrice) tp1Price = entryPrice - tp1Pips;
    if (tp2Price >= tp1Price) tp2Price = tp1Price - (tp2Pips - tp1Pips);
}

// Validar ratio riesgo/recompensa mínimo 1.5:1
const risk = Math.abs(entryPrice - stopPrice);
const reward1 = Math.abs(tp1Price - entryPrice);
const rrRatio = risk > 0 ? reward1 / risk : 0;

if (rrRatio < 1.5) {
    console.log(`⚠️ Ratio R/R ${rrRatio.toFixed(2)} < 1.5, ajustando TP1`);
    tp1Price = decision === "buy" ? entryPrice + (risk * 1.5) : entryPrice - (risk * 1.5);
}

// Redondear a decimales correctos
const decimals = isJPY ? 1000 : 100000;
entryPrice = Math.round(entryPrice * decimals) / decimals;
stopPrice = Math.round(stopPrice * decimals) / decimals;
tp1Price = Math.round(tp1Price * decimals) / decimals;
tp2Price = Math.round(tp2Price * decimals) / decimals;

// Limitar volumen (MAX 0.05)
volumeValue = Math.min(0.05, Math.max(0.01, volumeValue));
volumeValue = Math.round(volumeValue * 100) / 100;

// ============================================
// RESULTADO FINAL
// ============================================
const finalRR = Math.abs(entryPrice - stopPrice) > 0 ? 
    Math.abs(tp1Price - entryPrice) / Math.abs(entryPrice - stopPrice) : 0;

console.log("========================================");
console.log("📊 DATOS FINALES DEL ESTRATEGA:");
console.log(`   Símbolo: ${currentSymbol}`);
console.log(`   Decisión: ${decision.toUpperCase()}`);
console.log(`   Confianza: ${confidence}%`);
console.log(`   Precio entrada: ${entryPrice}`);
console.log(`   Stop Loss: ${stopPrice}`);
console.log(`   Take Profit 1: ${tp1Price}`);
console.log(`   Take Profit 2: ${tp2Price}`);
console.log(`   Volumen: ${volumeValue}`);
console.log(`   Ratio R/R: ${finalRR.toFixed(2)}:1`);
console.log("========================================");

const result = {
    decision: decision,
    confianza: confidence,
    razonamiento: `${decision.toUpperCase()} ${currentSymbol} con ${confidence}% confianza. R/R: ${finalRR.toFixed(2)}:1`,
    entrada: { precio: entryPrice, tolerancia: isJPY ? 0.05 : 0.0005 },
    stop_loss: { precio: stopPrice, pips: Math.round(Math.abs(entryPrice - stopPrice) * (isJPY ? 100 : 10000)) },
    take_profit: { objetivo1: tp1Price, objetivo2: tp2Price },
    volumen: volumeValue,
    convergence: { level: confidence >= 65 ? "high" : (confidence >= 45 ? "medium" : "low"), agents: ["technical", "fundamental", "sentiment"] },
    signals: { buy: decision === "buy" ? 3 : 0, sell: decision === "sell" ? 3 : 0 },
    symbol: currentSymbol
};

console.log("✅ AGENTE ESTRATEGA FINALIZADO");
console.log(`🎯 ${result.decision.toUpperCase()} ${currentSymbol} @ ${result.entrada.precio}`);

return [{ json: result }];

// ============================================
// AGENTE UNIFICADO - VERSIÓN CORREGIDA v2.0
// ============================================
// CORRECCIONES:
// 1. Extrae precios de TODOS los símbolos, no solo EURUSD
// 2. Usa precio del best_pair específico para análisis
// 3. Valida rangos de precios por símbolo
// ============================================

const allItems = $input.all();
console.log(`📦 Recibidos ${allItems.length} items para procesar`);

// ============================================
// CONFIGURACIÓN DE VALIDACIÓN
// ============================================
const VALID_RANGES = {
    EURUSD: { min: 1.05, max: 1.20 },
    GBPUSD: { min: 1.25, max: 1.40 },
    USDJPY: { min: 140.0, max: 170.0 },
    USDCHF: { min: 0.85, max: 1.00 }
};

const DEFAULT_PRICES = {
    EURUSD: 1.1689,
    GBPUSD: 1.3570,
    USDJPY: 159.88,
    USDCHF: 0.7996
};

function validatePrice(symbol, price, source) {
    if (price === null || price === undefined || isNaN(price)) {
        console.log(`⚠️ ${symbol}: ${source} inválido ${price}, usando default`);
        return DEFAULT_PRICES[symbol];
    }

    const range = VALID_RANGES[symbol];
    if (range && (price < range.min || price > range.max)) {
        console.log(`⚠️ ${symbol}: ${source} ${price} FUERA DE RANGO [${range.min}-${range.max}]`);
        return DEFAULT_PRICES[symbol];
    }

    console.log(`✅ ${symbol}: ${source} = ${price}`);
    return price;
}

// ============================================
// INICIALIZAR ESTRUCTURA DE DATOS
// ============================================
let marketData = {
    best_pair: "EURUSD",
    best_score: 0,
    all_prices: {}, // NUEVO: almacenar precios de todos los símbolos
    technical: {
        current_price: 0,
        rsi: 50,
        trend: "neutral",
        support: 0,
        resistance: 0,
        candles: []
    },
    fundamental: {
        news_count: 0,
        high_impact_events: 0,
        events: [],
        relevant_news: [],
        calendar_events: []
    },
    positions: {
        count: 0,
        exposure: 0,
        details: []
    },
    pending_orders: {
        count: 0,
        exposure: 0,
        details: []
    },
    risk: {
        account_balance: 100000,
        risk_amount: 2000,
        recommended_volume: 0.05,
        current_exposure: 0,
        pending_exposure: 0
    },
    currency_strength: {
        rates: {},
        strength: { EUR: "neutral", USD: "neutral", GBP: "neutral", JPY: "neutral", CHF: "neutral" },
        sentiment: { score: 0, overall: "neutral", market_mood: "calm" }
    }
};

// ============================================
// PROCESAR CADA ITEM DEL ARRAY ENTRANTE
// ============================================
for (const item of allItems) {
    const data = item.json;

    // Caso 1: Datos de cuenta (tiene balance, equity, profit)
    if (data.balance !== undefined && data.equity !== undefined) {
        marketData.risk.account_balance = data.balance;
        console.log(`💰 Cuenta detectada: Balance ${data.balance}`);
    }

    // Caso 2: Orden pendiente (tiene id, symbol, type, open, state="PLACED")
    if (data.id && data.symbol && data.type && data.state === "PLACED") {
        marketData.pending_orders.count = 1;
        marketData.pending_orders.exposure = data.volume || 0;
        marketData.pending_orders.details = [data];
        marketData.best_pair = data.symbol;
        console.log(`⏰ Orden pendiente: ${data.type} ${data.symbol} @ ${data.open}`);
    }

    // Caso 3: Fortaleza de divisas (tiene rates, strength, sentiment)
    if (data.rates && data.strength && data.sentiment) {
        marketData.currency_strength = {
            rates: data.rates,
            strength: data.strength,
            sentiment: data.sentiment
        };

        // EXTRAER PRECIOS DE TODOS LOS SÍMBOLOS (NO SOLO EURUSD)
        if (data.rates.EURUSD) {
            marketData.all_prices.EURUSD = validatePrice("EURUSD", data.rates.EURUSD, "rates");
        }
        if (data.rates.GBPUSD) {
            marketData.all_prices.GBPUSD = validatePrice("GBPUSD", data.rates.GBPUSD, "rates");
        }
        if (data.rates.USDJPY) {
            marketData.all_prices.USDJPY = validatePrice("USDJPY", data.rates.USDJPY, "rates");
        }
        if (data.rates.USDCHF) {
            marketData.all_prices.USDCHF = validatePrice("USDCHF", data.rates.USDCHF, "rates");
        }

        console.log(`💵 Precios extraídos: ${JSON.stringify(marketData.all_prices)}`);

        // Calcular tendencia basada en fortaleza de divisas
        const usdStrength = data.strength.USD || "neutral";
        const eurStrength = data.strength.EUR || "neutral";

        if (eurStrength === "bullish" && usdStrength === "bearish") {
            marketData.technical.trend = "bullish";
            marketData.technical.rsi = 65;
            marketData.best_score = 70;
        } else if (eurStrength === "bearish" && usdStrength === "bullish") {
            marketData.technical.trend = "bearish";
            marketData.technical.rsi = 35;
            marketData.best_score = 70;
        } else {
            marketData.technical.trend = "neutral";
            marketData.technical.rsi = 50;
            marketData.best_score = 30;
        }

        console.log(`📈 Tendencia: ${marketData.technical.trend}, RSI: ${marketData.technical.rsi}`);
    }

    // Caso 4: Precio directo de data fetcher (tiene symbol y bid)
    if (data.symbol && data.bid !== undefined) {
        const sym = data.symbol;
        marketData.all_prices[sym] = validatePrice(sym, data.bid, "bid directo");
    }
}

// ============================================
// ASEGURAR PRECIOS PARA TODOS LOS SÍMBOLOS
// ============================================
for (const [symbol, defaultPrice] of Object.entries(DEFAULT_PRICES)) {
    if (!marketData.all_prices[symbol]) {
        console.log(`⚠️ ${symbol}: No encontrado, usando default ${defaultPrice}`);
        marketData.all_prices[symbol] = defaultPrice;
    }
}

// ============================================
// ESTABLECER PRECIO ACTUAL DEL BEST_PAIR
// ============================================
// Si no se detectó best_pair, usar EURUSD
if (marketData.best_pair === "EURUSD" && marketData.best_score === 0) {
    // Intentar determinar mejor par desde fortaleza de divisas
    const strength = marketData.currency_strength.strength;
    let bestScore = 0;
    let bestPair = "EURUSD";

    const pairs = [
        { sym: "EURUSD", base: strength.EUR, quote: strength.USD },
        { sym: "GBPUSD", base: strength.GBP, quote: strength.USD },
        { sym: "USDJPY", base: strength.USD, quote: strength.JPY },
        { sym: "USDCHF", base: strength.USD, quote: strength.CHF }
    ];

    for (const pair of pairs) {
        let score = 50;
        if (pair.base === "bullish" && pair.quote === "bearish") score = 70;
        else if (pair.base === "bearish" && pair.quote === "bullish") score = 70;
        else if (pair.base === "neutral" && pair.quote === "neutral") score = 30;

        if (score > bestScore) {
            bestScore = score;
            bestPair = pair.sym;
        }
    }

    marketData.best_pair = bestPair;
    marketData.best_score = bestScore;
    console.log(`🏆 Mejor par determinado: ${bestPair} con score ${bestScore}`);
}

// USAR EL PRECIO CORRECTO DEL BEST_PAIR
const currentPrice = marketData.all_prices[marketData.best_pair] || DEFAULT_PRICES[marketData.best_pair];
marketData.technical.current_price = currentPrice;

console.log(`\n💰 PRECIO FINAL PARA ${marketData.best_pair}: ${currentPrice}`);
console.log(`   Todos los precios: ${JSON.stringify(marketData.all_prices)}\n`);

// ============================================
// CREAR CONTEXTO PARA AGENTES
// ============================================
const context = {
    market_data: marketData,
    memory: {
        agent_weights: { technical: 0.35, fundamental: 0.25, sentiment: 0.25, statistical: 0.15 },
        preferences: { risk_tolerance: 0.02, min_confidence: 45 },
        global_metrics: { total_trades: 0, winrate: 0 },
        performance: {
            technical: { winrate: 0 },
            fundamental: { winrate: 0 },
            sentiment: { winrate: 0 },
            statistical: { winrate: 0 }
        }
    }
};

// ============================================
// PREPARAR DATOS TÉCNICOS
// ============================================
const technicalData = {
    symbol: marketData.best_pair,
    price: marketData.technical.current_price,
    rsi: marketData.technical.rsi || 50,
    trend: marketData.technical.trend || "neutral",
    support: marketData.technical.support || 0,
    resistance: marketData.technical.resistance || 0,
    score: marketData.best_score || 0
};

const candles = marketData.technical.candles || [];
const lastCandle = candles[candles.length - 1] || {};
const prevCandle = candles[candles.length - 2] || {};

const candleBody = Math.abs((lastCandle.close || 0) - (lastCandle.open || 0));
const candleRange = (lastCandle.high || 0) - (lastCandle.low || 0);
const isBullishCandle = (lastCandle.close || 0) > (lastCandle.open || 0);
const isBearishCandle = (lastCandle.close || 0) < (lastCandle.open || 0);

const currentVolume = lastCandle.tick_volume || 0;
const prevVolume = prevCandle.tick_volume || 0;
const volumeChange = prevVolume > 0 ? ((currentVolume - prevVolume) / prevVolume * 100) : 0;

const sma20 = candles.slice(-20).reduce((sum, c) => sum + (c.close || 0), 0) / 20;
const sma50 = candles.slice(-50).reduce((sum, c) => sum + (c.close || 0), 0) / 50;

const rsiStatus = technicalData.rsi < 30 ? "oversold" : (technicalData.rsi > 70 ? "overbought" : "neutral");

const avgTrueRange = technicalData.symbol.includes("JPY") ? 0.5 : 0.003;
const volatilityPercent = (avgTrueRange / technicalData.price * 100).toFixed(2);

// ============================================
// PREPARAR DATOS FUNDAMENTALES
// ============================================
const fd = {
    symbol: marketData.best_pair,
    news_count: marketData.fundamental.news_count || 0,
    relevant_news: marketData.fundamental.relevant_news || [],
    calendar_events: marketData.fundamental.calendar_events || []
};

let usdNews = [];
let eurNews = [];

for (const news of fd.relevant_news) {
    const currency = news.currency || "";
    if (currency === "USD") usdNews.push(news);
    else if (currency === "EUR") eurNews.push(news);
}

const highImpactEventsList = fd.calendar_events.filter(e => e.impact === "high");
const upcomingEvents = highImpactEventsList.slice(0, 3).map(e => `${e.currency}:${e.event}`).join(', ');

// ============================================
// PREPARAR DATOS DE SENTIMIENTO
// ============================================
const positions = marketData.positions.details || [];
const pendingOrders = marketData.pending_orders.details || [];

let longVolume = 0, shortVolume = 0;
for (const p of positions) {
    const v = Math.abs(p.volume || 0);
    if (["buy", "long", "BUY"].includes(p.type)) longVolume += v;
    else if (["sell", "short", "SELL"].includes(p.type)) shortVolume += v;
}

let pendingLongVolume = 0, pendingShortVolume = 0;
for (const p of pendingOrders) {
    const v = Math.abs(p.volume || 0);
    if (p.type && p.type.includes("BUY")) pendingLongVolume += v;
    if (p.type && p.type.includes("SELL")) pendingShortVolume += v;
}

const totalLongVolume = longVolume + pendingLongVolume;
const totalShortVolume = shortVolume + pendingShortVolume;
const totalVolume = totalLongVolume + totalShortVolume;
let combinedRatio = 0;
if (totalVolume > 0) {
    combinedRatio = ((totalLongVolume - totalShortVolume) / totalVolume) * 100;
}

let sentimentLevel = "neutral";
if (combinedRatio > 60) sentimentLevel = "extreme_bullish";
else if (combinedRatio > 25) sentimentLevel = "bullish";
else if (combinedRatio < -60) sentimentLevel = "extreme_bearish";
else if (combinedRatio < -25) sentimentLevel = "bearish";

let contrarySignal = "none";
if (sentimentLevel === "extreme_bullish") contrarySignal = "sell";
else if (sentimentLevel === "extreme_bearish") contrarySignal = "buy";

// ============================================
// PREPARAR DATOS ESTADÍSTICOS
// ============================================
const globalMetrics = context.memory.global_metrics || {};
const preferences = context.memory.preferences || {};
const totalTrades = globalMetrics.total_trades || 0;
const winRate = globalMetrics.winrate || 0;
const riskTolerance = preferences.risk_tolerance || 0.02;
const accountBalance = marketData.risk.account_balance || 100000;

// ============================================
// CONSTRUIR PROMPT UNIFICADO
// ============================================
const isJPY = technicalData.symbol.includes("JPY");
const priceMultiplier = isJPY ? 0.002 : 0.002;

const unifiedPrompt = `You are a senior trading AI with 20 years of experience. Perform a COMPLETE market analysis for ${technicalData.symbol}.

========================================
TECHNICAL DATA
========================================
Symbol: ${technicalData.symbol}
Current Price: ${technicalData.price}  ⚠️ USE THIS EXACT PRICE FOR ALL CALCULATIONS
RSI (14): ${technicalData.rsi} (${rsiStatus})
Trend: ${technicalData.trend} | Score: ${technicalData.score}/100
Support: ${technicalData.support} | Resistance: ${technicalData.resistance}
Last Candle: ${isBullishCandle ? "BULLISH" : (isBearishCandle ? "BEARISH" : "NEUTRAL")}
Volume Change: ${volumeChange > 0 ? '+' : ''}${volumeChange.toFixed(1)}%
SMA 20: ${sma20.toFixed(isJPY ? 2 : 5)} | SMA 50: ${sma50.toFixed(isJPY ? 2 : 5)}
Volatility: ${volatilityPercent}%

========================================
FUNDAMENTAL DATA
========================================
News Articles: ${fd.news_count}
USD News: ${usdNews.length} | EUR News: ${eurNews.length}
Upcoming Events: ${upcomingEvents || "none"}

========================================
SENTIMENT DATA
========================================
Long Volume: ${totalLongVolume.toFixed(2)} lots
Short Volume: ${totalShortVolume.toFixed(2)} lots
Sentiment Score: ${combinedRatio.toFixed(1)}%
Sentiment Level: ${sentimentLevel.toUpperCase()}
Contrarian Signal: ${contrarySignal.toUpperCase()}

========================================
STATISTICAL DATA
========================================
Total Trades: ${totalTrades}
Win Rate: ${winRate}%
Risk Tolerance: ${(riskTolerance * 100).toFixed(0)}%
Account Balance: $${accountBalance}

========================================
⚠️ CRITICAL PRICE INSTRUCTIONS ⚠️
========================================
The CURRENT PRICE for ${technicalData.symbol} is EXACTLY ${technicalData.price}.

ALL your price values MUST use this price as reference:
- entry_zone: Must be within ±${(technicalData.price * priceMultiplier).toFixed(isJPY ? 2 : 5)} of ${technicalData.price}
- stop_zone: Must be within ${(technicalData.price * priceMultiplier * 1.5).toFixed(isJPY ? 2 : 5)} of ${technicalData.price}
