// ============================================
// PARSE UNIFICADO - VERSIÓN CORREGIDA v2.0
// ============================================
// CORRECCIONES:
// 1. Validación de rangos de precios extraídos
// 2. Soporte mejorado para pares JPY
// 3. Extrae precios correctos del contexto
// ============================================

console.log("========================================");
console.log("📥 PARSE UNIFICADO v2.0 - INICIANDO");
console.log("========================================");

// ============================================
// CONFIGURACIÓN DE VALIDACIÓN
// ============================================
const VALID_RANGES = {
    EURUSD: { min: 1.05, max: 1.20 },
    GBPUSD: { min: 1.25, max: 1.40 },
    USDJPY: { min: 140.0, max: 170.0 },
    USDCHF: { min: 0.85, max: 1.00 }
};

const DEFAULT_PRICES = {
    EURUSD: 1.1689,
    GBPUSD: 1.3570,
    USDJPY: 159.88,
    USDCHF: 0.7996
};

function validateExtractedPrice(symbol, price, field) {
    const range = VALID_RANGES[symbol];
    if (!range) return { valid: true, price };

    if (price === null || price === undefined || isNaN(price) || price === 0) {
        console.log(`⚠️ ${symbol}: ${field} inválido (${price})`);
        return { valid: false, price: DEFAULT_PRICES[symbol] };
    }

    // Ampliar rangos para TP/SL que pueden estar más lejos
    const extendedRange = {
        min: range.min - (range.max - range.min) * 0.1,
        max: range.max + (range.max - range.min) * 0.1
    };

    if (price < extendedRange.min || price > extendedRange.max) {
        console.log(`⚠️ ${symbol}: ${field} ${price} FUERA DE RANGO EXTENDIDO`);
        return { valid: false, price: DEFAULT_PRICES[symbol] };
    }

    return { valid: true, price };
}

// ============================================
// OBTENER CONTENIDO DE OPENROUTER
// ============================================
let content = "";

try {
    if ($json.choices && $json.choices[0] && $json.choices[0].message) {
        content = $json.choices[0].message.content;
    } else if ($json.content) {
        content = $json.content;
    } else if (typeof $json === 'string') {
        content = $json;
    } else {
        content = JSON.stringify($json);
    }

    console.log("✅ Contenido obtenido, longitud:", content.length);
} catch (e) {
    console.error("❌ Error obteniendo contenido:", e.message);
    content = "";
}

// ============================================
// OBTENER DATOS DE MERCADO DEL CONTEXTO
// ============================================
let contextData = {};
let currentPrice = 1.1689;
let trend = "neutral";
let currentSymbol = "EURUSD";

try {
    const prevNode = $node["Agente Unificado"];
    if (prevNode && prevNode.json && prevNode.json.context) {
        contextData = prevNode.json.context;
        const marketData = contextData.market_data || {};

        // Obtener símbolo actual
        currentSymbol = marketData.best_pair || "EURUSD";

        // USAR PRECIO DEL ALL_PRICES para el símbolo correcto
        if (marketData.all_prices && marketData.all_prices[currentSymbol]) {
            const priceFromAll = marketData.all_prices[currentSymbol];
            const validation = validateExtractedPrice(currentSymbol, priceFromAll, "all_prices");
            if (validation.valid) {
                currentPrice = priceFromAll;
            } else {
                currentPrice = validation.price;
            }
        } else if (marketData.technical?.current_price) {
            const priceFromTech = marketData.technical.current_price;
            const validation = validateExtractedPrice(currentSymbol, priceFromTech, "technical");
            if (validation.valid) {
                currentPrice = priceFromTech;
            } else {
                currentPrice = validation.price;
            }
        }

        trend = marketData.technical?.trend || "neutral";
    }
} catch (e) {
    console.log("⚠️ No se pudo obtener contexto, usando valores por defecto");
}

console.log(`💰 Símbolo: ${currentSymbol}`);
console.log(`💰 Precio actual: ${currentPrice}`);
console.log(`📈 Tendencia: ${trend}`);

// ============================================
// EXTRAER DECISIÓN DEL TEXTO
// ============================================
let decision = "hold";
let confidence = 50;

const textLower = content.toLowerCase();

if (textLower.includes("**buy**") || 
    textLower.includes("direction:** buy") ||
    (textLower.includes("buy") && !textLower.includes("sell") && textLower.includes("long"))) {
    decision = "buy";
    confidence = 70;
    console.log("✅ Decisión detectada: BUY");
} else if (textLower.includes("**sell**") || 
           textLower.includes("direction:** sell") ||
           textLower.includes("short")) {
    decision = "sell";
    confidence = 70;
    console.log("✅ Decisión detectada: SELL");
} else if (textLower.includes("hold") || textLower.includes("wait")) {
    decision = "hold";
    confidence = 30;
    console.log("⚠️ Decisión detectada: HOLD");
} else {
    console.log("⚠️ No se detectó decisión clara, usando tendencia");
    if (trend === "bullish") {
        decision = "buy";
        confidence = 55;
    } else if (trend === "bearish") {
        decision = "sell";
        confidence = 55;
    }
}

// ============================================
// EXTRAER NIVELES DE PRECIO CON VALIDACIÓN
// ============================================
const isJPY = currentSymbol.includes("JPY");

// Función para validar precio extraído
function isValidExtractedPrice(val, symbol) {
    if (val === null || val === undefined || isNaN(val) || val === 0) return false;
    const range = VALID_RANGES[symbol];
    if (!range) return true;
    // Ampliar rango para SL/TP
    const extendedMin = range.min - (range.max - range.min) * 0.2;
    const extendedMax = range.max + (range.max - range.min) * 0.2;
    return val >= extendedMin && val <= extendedMax;
}

// Entry zone
let entryLow = currentPrice * (isJPY ? 0.999 : 0.999);
let entryHigh = currentPrice * (isJPY ? 1.001 : 1.001);

const entryPatterns = [
    /entry zone[:\s]*[*]*\[([0-9.]+),\s*([0-9.]+)\]/i,
    /entry[:\s]*\[([0-9.]+)[,\s]+([0-9.]+)\]/i,
    /between\s+([0-9.]+)\s+and\s+([0-9.]+)/i
];

for (const pattern of entryPatterns) {
    const match = content.match(pattern);
    if (match && match[1] && match[2]) {
        const val1 = parseFloat(match[1]);
        const val2 = parseFloat(match[2]);
        if (isValidExtractedPrice(val1, currentSymbol) && isValidExtractedPrice(val2, currentSymbol)) {
            entryLow = val1;
            entryHigh = val2;
            console.log(`📊 Entry zone encontrada: ${entryLow} - ${entryHigh}`);
            break;
        }
    }
}

// Stop loss
let stopLow = currentPrice * (isJPY ? 0.997 : 0.997);
let stopHigh = currentPrice * (isJPY ? 1.003 : 1.003);

const stopPatterns = [
    /stop[-\s]*loss[:\s]*[*]*\[([0-9.]+),\s*([0-9.]+)\]/i,
    /stop[:\s]*\[([0-9.]+)[,\s]+([0-9.]+)\]/i,
    /stop[-]loss[:\s]*([0-9.]+)/i
];

for (const pattern of stopPatterns) {
    const match = content.match(pattern);
    if (match) {
        if (match[1] && match[2]) {
            const val1 = parseFloat(match[1]);
            const val2 = parseFloat(match[2]);
            if (isValidExtractedPrice(val1, currentSymbol) && isValidExtractedPrice(val2, currentSymbol)) {
                stopLow = val1;
                stopHigh = val2;
                console.log(`📊 Stop loss encontrado: ${stopLow} - ${stopHigh}`);
                break;
            }
        } else if (match[1]) {
            const val = parseFloat(match[1]);
            if (isValidExtractedPrice(val, currentSymbol)) {
                if (decision === "buy") {
                    stopLow = val;
                    stopHigh = val + (isJPY ? 0.5 : 0.001);
                } else {
                    stopLow = val - (isJPY ? 0.5 : 0.001);
                    stopHigh = val;
                }
                console.log(`📊 Stop loss encontrado: ${stopLow} - ${stopHigh}`);
                break;
            }
        }
    }
}

// Take profits
let tp1 = decision === "buy" ? currentPrice * (isJPY ? 1.003 : 1.003) : currentPrice * (isJPY ? 0.997 : 0.997);
let tp2 = decision === "buy" ? currentPrice * (isJPY ? 1.005 : 1.005) : currentPrice * (isJPY ? 0.995 : 0.995);

const tp1Patterns = [
    /take[-\s]*profit[-\s]*1[:\s]*[*]*([0-9.]+)/i,
    /tp1[:\s]*([0-9.]+)/i,
    /profit\s+1[:\s]*([0-9.]+)/i
];

for (const pattern of tp1Patterns) {
    const match = content.match(pattern);
    if (match && match[1]) {
        const val = parseFloat(match[1]);
        if (isValidExtractedPrice(val, currentSymbol)) {
            tp1 = val;
            console.log(`📊 TP1 encontrado: ${tp1}`);
            break;
        }
    }
}

const tp2Patterns = [
    /take[-\s]*profit[-\s]*2[:\s]*[*]*([0-9.]+)/i,
    /tp2[:\s]*([0-9.]+)/i,
    /profit\s+2[:\s]*([0-9.]+)/i
];

for (const pattern of tp2Patterns) {
    const match = content.match(pattern);
    if (match && match[1]) {
        const val = parseFloat(match[1]);
        if (isValidExtractedPrice(val, currentSymbol)) {
            tp2 = val;
            console.log(`📊 TP2 encontrado: ${tp2}`);
            break;
        }
    }
}

// Volumen
let volume = 0.04;
const volumeMatch = content.match(/(\d+\.?\d*)\s*(?:standard\s*)?lots?/i);
if (volumeMatch) {
    const vol = parseFloat(volumeMatch[1]);
    if (vol > 0 && vol <= 0.05) {
        volume = Math.min(0.05, Math.max(0.01, vol));
        console.log(`📊 Volumen encontrado: ${volume} lots`);
    }
}

// Redondear valores
const decimals = isJPY ? 1000 : 100000;
entryLow = Math.round(entryLow * decimals) / decimals;
entryHigh = Math.round(entryHigh * decimals) / decimals;
stopLow = Math.round(stopLow * decimals) / decimals;
stopHigh = Math.round(stopHigh * decimals) / decimals;
tp1 = Math.round(tp1 * decimals) / decimals;
tp2 = Math.round(tp2 * decimals) / decimals;

console.log("========================================");
console.log("📊 DATOS FINALES EXTRACCIÓN:");
console.log(`   Símbolo: ${currentSymbol}`);
console.log(`   Decisión: ${decision.toUpperCase()}`);
console.log(`   Confianza: ${confidence}%`);
console.log(`   Entry: ${entryLow} - ${entryHigh}`);
console.log(`   Stop: ${stopLow} - ${stopHigh}`);
console.log(`   TP1: ${tp1}`);
console.log(`   TP2: ${tp2}`);
console.log(`   Volumen: ${volume}`);
console.log("========================================");

// ============================================
// CONSTRUIR RESULTADO
// ============================================
const resultState = {
    tecnico: {
        señal: decision,
        confianza: confidence,
        analisis: `${decision.toUpperCase()} setup for ${currentSymbol}`,
        estructura: decision === "buy" ? "bullish" : (decision === "sell" ? "bearish" : "range"),
        momento: "moderate",
        volatilidad: "normal",
        entry_zona: [entryLow, entryHigh],
        stop_zona: [stopLow, stopHigh],
        take_profit_1: tp1,
        take_profit_2: tp2,
        risk_reward_ratio: Math.abs((tp1 - entryLow) / (entryLow - stopLow)).toFixed(2),
        volumen_signal: "neutral",
        vela_signal: decision === "buy" ? "bullish" : "neutral"
    },
    fundamental: {
        recomendacion: decision === "hold" ? "wait" : "act",
        confianza: Math.max(0, confidence - 10),
        analisis: `Fundamental analysis for ${currentSymbol}`,
        direccion_impacto: decision === "buy" ? "bullish" : (decision === "sell" ? "bearish" : "neutral"),
        riesgo_noticioso: "low",
        sentimiento: decision === "buy" ? 20 : (decision === "sell" ? -20 : 0),
        central_bias: "neutral",
        volatilidad_esperada: "medium",
        eventos_clave: []
    },
    sentimiento: {
        sentimiento: decision === "buy" ? "bullish" : (decision === "sell" ? "bearish" : "neutral"),
        confianza: Math.max(0, confidence - 5),
        analisis: `Sentiment analysis for ${currentSymbol}`,
        señal_contraria: "none",
        puntuacion: 0,
        market_mood: "calm",
        divergencia: "none",
        extremo: false
    },
    estadistico: {
        volatilidad_estado: "normal",
        ajuste_volumen: 1.0,
        probabilidad_continuacion: 65,
        confianza: Math.max(0, confidence - 15),
        analisis: `Statistical analysis for ${currentSymbol}`,
        riesgo_score: 40,
        sharpe_estimado: 0.8
    }
};

const output = [{
    json: {
        original: contextData,
        state: resultState,
        _extracted: {
            decision: decision,
            confidence: confidence,
            entry: [entryLow, entryHigh],
            stop: [stopLow, stopHigh],
            tp1: tp1,
            tp2: tp2,
            volume: volume,
            symbol: currentSymbol
        }
    }
}];

console.log("✅ PARSE UNIFICADO v2.0 COMPLETADO");
console.log(`🎯 OUTPUT FINAL: ${decision.toUpperCase()} ${currentSymbol} con ${confidence}% confianza`);

return output;
